INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05100', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '靈公好婦人而丈夫飾者，國人盡服之。公使吏禁之，曰：「女子而男子飾者，裂其 衣，斷其帶。」裂衣斷帶相望，而不止。晏子見，公問曰：「寡人使吏禁女子而男 子飾，裂斷其衣帶，相望而不止者何也？」晏子對曰：「君使服之于內，而禁之于 外，猶懸牛首于門，而賣馬肉于內也。公何以不使內勿服，則外莫敢為也。」公曰： 「善。」使內勿服，踰月，而國莫之服。（《晏子春秋‧內篇雜下》） 根據上文，靈公令出而不能禁者，下列選項何者解釋最為恰當？', '["靈公服裝禁令止行於宮外，禁令並不行於宮內", "靈公內有喜歡之婦，就命令男子來扮成其模樣", "靈公外表雖禁止，但內在仍然喜歡女子著男裝", "靈公之令只有禁止穿於內服，並不禁止著於外"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05101', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '白居易〈點額魚〉：「龍門點額意何如，紅尾青鬐卻返初。見說在天行雨苦，為龍 未必勝為魚。」依據詩旨，作者想表達的觀點是：', '["人無遠慮，必有近憂", "寬慰失敗，自求坦然", "克服弱點，方能求勝", "人生苦短，行樂及時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05102', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「吾知藏諸閭閻者，君皆得而有之，不必歸之府庫而後為吾財也；蓄諸田野者，君 皆得而用之，不必積之倉廩而後為吾有也。」下列選項，何者符合這段話的旨意？', '["用之則行，舍之則藏", "百姓足，君孰與不足", "士見危致命，見得思義", "君子食無求飽，居無求安"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05103', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '客有過主人者，見其灶直突，傍有積薪，客謂主人，更為曲突，遠徙其薪，不者且 有火患。主人嘿（默）然不應。俄而家果失火，鄰里共救之，幸而得息。於是殺牛 置酒，謝其鄰人，灼爛者在於上行，餘各以功次坐，而不錄言曲突者。人謂主人曰： 「鄉（曏）使聽客之言，不費牛酒，終亡火患。今論功而請賓，曲突徙薪亡恩澤， 焦頭爛額為上客耶？」主人乃寤而請之。（《漢書．霍光傳》） 根據上文的寓意，比擬於現代企業的職責，下列選項較為符合的是：', '["曲突徙薪者是品質管理人", "焦頭爛額者是高階經理人", "論功請賓者是安全管理人", "仗義執言者是成效稽核人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05104', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '讀書無論資性高低，但能勤學好問，凡事思一個所以然，自有義理貫通之日；立身 不嫌家世貧賤，但能忠厚老成，所行無一毫苟且處，便為鄉黨仰望之人。（王永彬 《圍爐夜話》） 下列選項，何者符合上文旨意？', '["道德學問，任其自然", "讀書立身，不露鋒芒", "學貴有疑，人貴有德", "勤學修身，絕俗超塵"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05105', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「我喜歡這個無人出入的後院，尤其裡面散發出來野熟同存的氣味，讓人難以分辨 這究竟是有人料理安排，或是率性自然的本來模樣。可說是在蓄意與荒蕪間、惚恍 難分的一種土地狀態。農民們日日踏踩著土地、間或望著天空日頭，他們知道一些 宇宙運行的規則，因此得以安心篤定。我對土地的恐懼，或就是因為對於每一塊土 地，我都自覺猶如一片浮雲一個過客，因而難以相互對話與真實了解吧？」 根據上文，下列敘述何者正確？', '["自然美景遠勝人工斧鑿痕跡，身處其中更應仔細體驗", "作者肯定農民辛勞付出的踏實生活，強調應愛惜農作", "身為浮雲遊子，客座他鄉格外容易引發對家鄉的思念", "因生活方式差異，作者與農民對土地的情感有所不同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05106', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「即使學生能夠回饋的學習成效是那麼有限，我試著不去看他們可以到達什麼應該 到達的目的地，而是感受他們離開了起點有多遠；我試著不要用被訓練的標準測量 方法去丈量他們被規定應該要到達的距離，而是透過更多不同的方法來發現他們蹣 跚前進的軌跡。」 根據上文，下列選項何者最貼近作者想要表達的觀點？', '["教科書完全不適用於教學，不可墨守成規", "統計學完全不可信，要看教學現場而調整", "因材施教之後，學生都可以達到一致目標", "學生的程度不一，老師要能觀察個別差異"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05107', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「在天地的大美之中，語言只是醇釀所剩的糟粕，有口無心的人，才會喧囂不休。 而語言背後所包孕的慾濤念流、偏知成見，到這裡，也都該消融為眾水的昭澈、群 山的靜穆；或者是草木蟲魚鳥獸的生息；或者是空靈的風聲、水響與鷇音。」 下列選項，何者與本段引文主旨最接近？', '["擁抱自然讓人享受孤獨", "寫景文字貴在情景交融", "適時沉默是處世的哲學", "天地之美當以心靈感受"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05108', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列選項，何者是描寫晨昏的景象？', '["香剎夜忘歸，松青古殿扉", "夕陽依舊壘，寒磬滿空林", "日出而林霏開，雲歸而巖穴暝", "故鄉今夜思千里，霜鬢明朝又一年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05109', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「塞下秋來風景異，衡陽雁去無留意。四面邊聲連角起，千嶂裏，長煙落日孤城閉。 濁酒一杯家萬里，燕然未勒歸無計。羌管悠悠霜滿地，人不寐，將軍白髮征夫淚。」 （范仲淹〈漁家傲〉） 依據上文，下列選項何者錯誤？', '["道出作者有滅敵報國的雄心壯志", "敘述作者對久戍邊疆將士的同情", "著眼戰鬥驚心動魄與邊塞荒涼之景", "就內容推斷，應是描寫駐守邊疆的情景"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
